// Extract Tally field responses into a flat object
// Tally sends: { data: { fields: [{key, label, value}] } }
const fields = $input.item.json.data?.fields ?? [];

const get = (label) => {
  const f = fields.find(f => f.label?.toLowerCase().includes(label.toLowerCase()));
  return f?.value ?? null;
};

const getMulti = (label) => {
  const f = fields.find(f => f.label?.toLowerCase().includes(label.toLowerCase()));
  if (!f?.value) return [];
  if (Array.isArray(f.value)) return f.value;
  return [f.value];
};

// Map Tally fields to workspace schema
const intake = {
  buyer_name: get('first name') ?? get('name'),
  buyer_email: get('email'),
  business_name: get('business name') ?? get('calling it'),
  tagline: get('one sentence') ?? get('tagline'),
  business_type: get('category') ?? get('describes your business'),
  platforms: getMulti('sell') ?? getMulti('find customers') ?? getMulti('platforms'),
  revenue_model: get('make money') ?? get('revenue'),
  target_audience: get('ideal customer') ?? get('audience'),
  launch_date: get('launch'),
  monthly_revenue_goal: parseInt(get('monthly revenue goal') ?? get('revenue goal') ?? '0', 10) || null,
  startup_budget: parseInt(get('invest') ?? get('budget') ?? '0', 10) || null,
  experience_level: get('experience'),
  brand_color: get('brand color') ?? get('colour') ?? get('color'),
};

return { intake };

const { intake } = $input.item.json;

// Generate slug from business name
function generateSlug(name) {
  const base = (name ?? 'my-biz')
    .toLowerCase()
    .replace(/[^a-z0-9\s]/g, '')
    .trim()
    .split(/\s+/)
    .slice(0, 2)
    .join('-');
  const suffix = Math.random().toString(36).substring(2, 4);
  return `${base}-${suffix}`.substring(0, 12);
}

// Generate secure 64-char token
function generateToken(len = 64) {
  const chars = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789';
  return Array.from({length: len}, () => chars[Math.floor(Math.random() * chars.length)]).join('');
}

// Derive brand color from business type if not provided
function getBrandColor(type, provided) {
  if (provided && /^#[0-9A-Fa-f]{6}$/.test(provided)) return provided;
  const map = {
    'Handmade': '#B8860B',
    'Digital': '#6366F1',
    'Service': '#0EA5E9',
    'Food': '#F59E0B',
    'Fashion': '#EC4899',
    'Health': '#10B981',
    'Creative': '#8B5CF6',
  };
  for (const [key, color] of Object.entries(map)) {
    if ((type ?? '').includes(key)) return color;
  }
  return '#B8860B';
}

const slug = generateSlug(intake.business_name);
const access_token = generateToken(64);
const brand_color = getBrandColor(intake.business_type, intake.brand_color);

return {
  intake,
  slug,
  access_token,
  brand_color,
};

