const prev = $input.item.json;
const claudeOutput = prev.content?.[0]?.text ?? prev.text ?? '{}';

let generated;
try {
  // Strip any markdown code fences if Claude added them
  const cleaned = claudeOutput.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  generated = JSON.parse(cleaned);
} catch(e) {
  generated = { runway: [], content_prompts: [], offer_card: {}, pricing_guide: [], startup_costs: [] };
}

// Merge runway phases + startup_costs into runway_state structure
// runway_state.phases is the array of {name, items}
// runway_state.startup_costs is the cost breakdown
// content_state.prompts is the 30-day calendar

const runway_state = {
  phases: generated.runway ?? [],
  pricing_guide: generated.pricing_guide ?? [],
  startup_costs: generated.startup_costs ?? [],
};

const content_state = {
  prompts: generated.content_prompts ?? [],
};

const offer_card = generated.offer_card ?? {};

// Pass through all context
return {
  ...prev,
  runway_state,
  content_state,
  offer_card,
};

const prev = $input.item.json;
const appUrl = 'https://app.sidehustlecommandcentre.com';
const workspaceUrl = `${appUrl}/${prev.slug}?t=${prev.access_token}`;
const referralUrl = `${appUrl}/r/${prev.slug}`;

return {
  ...prev,
  workspace_url: workspaceUrl,
  referral_url: referralUrl,
};
